class Solution {
public:
    int minimumOperationsToMakeEqual(int x, int y) {
        queue<int> q;
        unordered_set<int> visited;
        q.push(x);
        visited.insert(x);
        int steps = 0;
        while (!q.empty()) {
            int size = q.size();
            for (int i = 0; i < size; i++) {
                int curr = q.front();
                q.pop();
                if (curr == y) return steps;
                if (curr + 1 <= 10000 && visited.find(curr + 1) == visited.end()) {
                    q.push(curr + 1);
                    visited.insert(curr + 1);
                }
                if (curr - 1 >= 1 && visited.find(curr - 1) == visited.end()) {
                    q.push(curr - 1);
                    visited.insert(curr - 1);
                }
                if (curr % 11 == 0 && visited.find(curr / 11) == visited.end()) {
                    q.push(curr / 11);
                    visited.insert(curr / 11);
                }
                if (curr % 5 == 0 && visited.find(curr / 5) == visited.end()) {
                    q.push(curr / 5);
                    visited.insert(curr / 5);
                }
            }
            steps++;
        }
        return -1;
    }
};
